                &#x2F;&#x2F; 登录表单 form 中用户名输入框 input 的 name 名， 不改的话默认是 username
                .usernameParameter(&quot;uname&quot;)
                &#x2F;&#x2F; form 中密码输入框 input 的 name 名，不改默认是 password
                .passwordParameter(&quot;pword&quot;)
