5.2.4.5 TokenAuthFilter 请求拦截进行授权的 Filter，过滤器会去获取请求头中的 Token，对 Token 进行解析取出其中的 username。使用 username 去 Redis 中获取对应的 权限列表。然后封装 Authentication 对象存 SecurityContextHolder。
在 Spring Security中，会使用默认的 FilterSecurityInterceptor 来进行权限校验。在 FilterSecurityInterceptor 中会从 SecurityContextHolder 获取其中的 Authentication，然后获取其中的权限信息。当前用户是否拥有访问当前资源所需的权限。在项目中只需要把当前登录用户的权限信息也存入Authentication。然后设置资源所需要的权限即可。
@AllArgsConstructor
public class TokenAuthFilter extends OncePerRequestFilter &#123;

    private TokenManager tokenManager;
    private RedisTemplate redisTemplate;

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain chain) throws IOException, ServletException &#123;
        &#x2F;&#x2F; 获取当前认证成功用户权限信息
        UsernamePasswordAuthenticationToken authRequest &#x3D; getAuthentication(request);
        &#x2F;&#x2F; 判断如果有权限信息，放到权限上下文中，是一个 Authentication 对象
        if(authRequest !&#x3D; null) &#123;
            SecurityContextHolder.getContext().setAuthentication(authRequest);
        &#125;
        chain.doFilter(request,response);
    &#125;

    private UsernamePasswordAuthenticationToken getAuthentication(HttpServletRequest request) &#123;
        &#x2F;&#x2F; 从 header获取 Token
        String token &#x3D; request.getHeader(&quot;token&quot;);
        if(token !&#x3D; null) &#123;
            &#x2F;&#x2F; 从 Token 获取用户名
            String username &#x3D; tokenManager.getUserInfoFromToken(token);
            &#x2F;&#x2F; 根据用户名从 Redis 获取对应权限列表
            List&lt;String&gt; permissionValueList &#x3D; (List&lt;String&gt;)redisTemplate.opsForValue().get(username);
            Collection&lt;GrantedAuthority&gt; authority &#x3D; new ArrayList&lt;&gt;();
            for(String permissionValue : permissionValueList) &#123;
                SimpleGrantedAuthority auth &#x3D; new SimpleGrantedAuthority(permissionValue);
                authority.add(auth);
            &#125;
            &#x2F;&#x2F; Authentication 的实现类
            return new UsernamePasswordAuthenticationToken(username, token, authority);
        &#125;
        return null;
    &#125;
&#125;
5.2.4.6 DefaultPasswordEncoder 加密加密处理
