6. 插件6.1 概念用于增强 Vue，包含 install 方法的一个对象，install 的第一个参数是 Vue，第二个以后的参数是插件使用者传递的数据。

定义插件： 对象.install &#x3D; function (Vue, options) &#123;
	&#x2F;&#x2F; 1. 添加全局过滤器
	Vue.filter(....)
	&#x2F;&#x2F; 2. 添加全局指令
	Vue.directive(....)
	&#x2F;&#x2F; 3. 配置全局混入(合)
	Vue.mixin(....)
	&#x2F;&#x2F; 4. 添加实例方法
	Vue.prototype.$myMethod &#x3D; function () &#123;...&#125;
	&#x2F;&#x2F; 5. 给 Vue 原型上添加一个方法（vm 和 vc 都能用）
	Vue.prototype.$myProperty &#x3D; xxxx
&#125;
使用插件：Vue.use()

6.2 使用定义一个插件 plugins.js
export default &#123;
	install(Vue, x, y, z)&#123;

		console.log(Vue, x, y, z)
		&#x2F;&#x2F;全局过滤器
		Vue.filter(&#39;mySlice&#39;,function(value)&#123;
			return value.slice(0,  4)
		&#125;)

		&#x2F;&#x2F;定义全局指令
		Vue.directive(&#39;fbind&#39;,&#123;
			&#x2F;&#x2F;指令与元素成功绑定时（一上来）
			bind(element,binding)&#123;
				element.value &#x3D; binding.value
			&#125;,
			&#x2F;&#x2F;指令所在元素被插入页面时
			inserted(element)&#123;
				element.focus()
			&#125;,
			&#x2F;&#x2F;指令所在的模板被重新解析时
			update(element,binding)&#123;
				element.value &#x3D; binding.value
			&#125;
		&#125;)

		&#x2F;&#x2F;定义混入
		Vue.mixin(&#123;
			data() &#123;
				return &#123;
					x:100,
					y:200
				&#125;
			&#125;,
		&#125;)

		&#x2F;&#x2F; 给 Vue原型上添加一个方法（vm 和 vc 都能用）
		Vue.prototype.hello &#x3D; ()&#x3D;&gt;&#123;alert(&#39;你好啊&#39;)&#125;
	&#125;
&#125;
