18.10 路由组件的生命周期钩子路由组件所独有的两个钩子，用于捕获路由组件的激活状态

activated ：路由组件被激活时触发
deactivated ：路由组件非激活时触发

&lt;script&gt;
	export default &#123;
		name:&#39;News&#39;,
		data() &#123;
			return &#123;
				opacity:1
			&#125;
		&#125;,
		activated() &#123;
			console.log(&#39;News组件被激活了&#39;)
			this.timer &#x3D; setInterval(() &#x3D;&gt; &#123;
				this.opacity -&#x3D; 0.01
				if(this.opacity &lt;&#x3D; 0) this.opacity &#x3D; 1
			&#125;,16)
		&#125;,
		deactivated() &#123;
